```rust
// Show runtime state in status command
async fn show_status(config: &Config, state: &StateStore, runtime: &RuntimeState) {
    let effective = runtime.get_effective_proxy().await;
    let is_failover = runtime.is_failed_over();

    if is_failover {
        println\!("Active Proxy: {} (FAILOVER from {})", 
            effective.as_deref().unwrap_or("none"),
            runtime.original_proxy.as_deref().unwrap_or("unknown"));
        if let Some(at) = runtime.failover_at {
            println\!("  Failover at: {} ({} ago)", at, format_duration(Utc::now() - at));
        }
    } else {
        println\!("Active Proxy: {}", effective.as_deref().unwrap_or("none"));
    }
}
